}

module example-one {
  namespace "tag:example.com,2017:example-one";
  prefix one;
  import example-foo { prefix f; }
  import example-bar { prefix b; }

  augment "/f:foo" {
    leaf foo { type b:foo; }
  }
}

leaf type {
  type enumeration {
    enum a;
    enum b;
    enum c;
  }
  mandatory true;
}
choice type-choice {
  case b {
    container type-b {
      when "../type = 'b'";
      leaf foo {
        type string;
      }
    }
  }
  case c {
    container type-c {
      when "../type = 'c'";
      leaf bar {
        mandatory true;
        type string;
      }
    }
  }
}

leaf type {
  type enumeration {
    enum a;
    enum b;
    enum c;
  }
  mandatory true;
}
container type-b {
  when "../type = 'b'";
  leaf foo {
    type string;
  }
}
container type-c {
  when "../type = 'c'";
  leaf bar {
    mandatory true;
    type string;
  }
}

leaf type {
  type enumeration {
    enum a;
    enum b;
    enum c;
  }
}
choice second-type {
  mandatory true;
  case foo {
    container foo {
      presence "When present, indicates type foo";
      leaf foo-attribute {
        type string;
      }
    }
  }
  case b {
    container bar {
      when "../type = 'a' or ../type = 'b'";
      presence "When present, indicates type bar";
      leaf bar-attribute {
        type string;
      }
    }
  }
  case c {
    container baz {
      when "../type = 'c'";
      leaf baz-attribute {
        mandatory true;
        type string;
      }
    }
  }
}

notification foo {
  leaf mtu {
    // NOT okay because when-stmt context is this notification
    when "/if:interfaces/if:interface[name='eth0']";
    type leafref {
      // Okay because path-stmt has a different context
      path "/if:interfaces/if:interface/if:mtu";
    }
  }
}

// assume "ex" is the prefix of the module where the identity
// name-format-null is defined

// do not use
when "md-name-format = 'name-format-null'";

// this is preferred
when "derived-from-or-self(md-name-format, 'ex:name-format-null')";

augment "/rt:active-route/rt:input/rt:destination-address" {
  when "derived-from-or-self(rt:address-family, "
     + "'v4ur:ipv4-unicast')" {
    description
      "This augment is valid only for IPv4 unicast.";
  }
  // nodes defined here within the augment-stmt
  // cannot be referenced in the when-stmt
}

when /foo/services/*/active {
  description
    "No services directly defined in this module.
     Matches objects that have augmented the services container.";
}

leaf foo1 {
  type enumeration {
    enum one;
    enum two;
    enum three;
  }
}

leaf foo2 {
  // INCORRECT
  must "/f:foo1 != 'two'";
  type string;
}
leaf foo2 {
  // CORRECT
  must "/f:foo1 = 'one' or /f:foo1 = 'three'";
  type string;
}

leaf foo1 {
  type enumeration {
    enum one;
    enum two;
    enum three;
    enum four;
  }
}

import ietf-yang-types {
   prefix yang;
   reference "RFC 9911: Common YANG Data Types";
}

leaf reserved {
