  }
}

identity foo-type {
  description "Base for the extensible type";
}

identity one {
  base f:foo-type;
}

identity two {
  base f:foo-type;
}

leaf foo {
  type identityref {
    base f:foo-type;
  }
}

typedef ipv6-address-no-zone {
  type inet:ipv6-address {
    pattern '[0-9a-fA-F:\.]*';
  }
  ...
}

typedef yang-identifier {
  type string {
    length "1..max";
    pattern '[a-zA-Z_][a-zA-Z0-9\-_.]*';
    pattern '.|..|[^xX].*|.[^mM].*|..[^lL].*';
  }
  ...
}

typedef dscp {
  type uint8 {
    range "0..63";
  }
  ...
}

leaf foo {
  // INCORRECT
  type enumeration {
    enum one;
    enum two;
  }
  description
    "The foo enum...
     one: The first enum
     two: The second enum";
}
leaf foo {
  // CORRECT
  type enumeration {
    enum one {
      description "The first enum";
    }
    enum two {
      description "The second enum";
    }
  }
  description
    "The foo enum...  ";
}

type union {
  type string;
  type enumeration {
    enum up;
    enum down;
  }
}

type union {
  type enumeration {
    enum up;
    enum down;
  }
  type string;
}

type union {
  type string;
  type int32;
}

type union {
  type int32;
  type string;
}

leaf flag1 {
  type empty;
}

leaf flag2 {
  type boolean;
  default false;
}

container top {
   container foos {
      list foo { ... }
   }
   container bars {
      list bar { ... }
   }
}

container top {
   list foo { ... }
   list bar { ... }
}

notification interface-up {
  description "Sent when an interface is activated.";
  leaf name {
    type leafref {
      path "/if:interfaces/if:interface/if:name";
    }
  }
}

feature feature1 {
  description "Some protocol feature";
}

feature feature2 {
  if-feature "feature1";
  description "Another protocol feature";
}

augment "/if:interfaces/if:interface" {
    when "if:type = 'ianaift:ethernetCsmacd'";

    container ethernet {
        leaf duplex {
            ...
        }
    }
}

module example-module {

  yang-version 1.1;
  namespace "tag:example.com,2017:example-module";
  prefix mymod;

  import iana-if-type { prefix iana; }
  import ietf-interfaces { prefix if; }

  identity some-new-iftype {
    base iana:iana-interface-type;
  }

  augment "/if:interfaces/if:interface" {
    when "if:type = 'mymod:some-new-iftype'";

    leaf mandatory-leaf {
      type string;
      mandatory true;
    }
  }
}

container backups {
  list backup {
    ...
    max-elements 10;
    ...
  }
}

deviation /bk:backups/bk:backup {
  deviate add {
    max-elements 10;
  }
}

list foo {
   key name;
   leaf name {
      type string;
   }
   ...
}

list foo-addon {
   key name;
   config false;
   leaf name {
      type string;
   }
   ...
}

list foo {
   key name;
   leaf name {
      type string;
   }
   ...
}

list foo-addon {
   key name;
   config false;
   leaf name {
      type leafref {
         path "/foo/name";
         require-instance false;
      }
   }
   leaf addon {
      type string;
      mandatory true;
   }
}

container foo {
  ...
